        for (int i = 0; i < M; i++) {
            int my_wall_row = (human_wall_assignment[i] == 0) ? top_wall_row : bot_wall_row;
            bool* my_claimed = (human_wall_assignment[i] == 0) ? col_claimed_top : col_claimed_bot;

            if (my_wall_row <= 0) {
