                                if (!can_build_wall(my_wall_row, c)) continue;
                                bool adjacent = false;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row &&
                                        humans[i].c + DC[d] == c) {
