                    safe_r = std::min(GRID_SIZE, wr + (GRID_SIZE - wr) / 2);
                }
                int safe_c = GRID_SIZE / 2;
                Point target = {safe_r, safe_c};

                if (!passable(target.r, target.c)) {
                    int search_start, search_end;
                    if (human_wall_assignment[i] == 0) {
                        search_start = 1;
                        search_end = (top_wall_row > 0) ? top_wall_row - 1 : GRID_SIZE;
                    } else {
                        search_start = (bot_wall_row > 0) ? bot_wall_row + 1 : 1;
                        search_end = GRID_SIZE;
                    }
                    bool found = false;
                    for (int r = search_start; r <= search_end && !found; r++) {
                        for (int c = 1; c <= GRID_SIZE && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }

                if (humans[i] == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
