constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Strategy: Sequential dual wall with edge-inward sweep construction.
// All humans build wall 1 first (fast), then wall 2.
// Walls are built from columns 1 and 30 inward, creating a single narrowing gap.
// Wall rows chosen to minimize pets in safe zones initially.

int wall_rows[2]; // wall_rows[0] = first wall, wall_rows[1] = second wall
int wall_safe_side[2]; // -1 = safe zone above, +1 = safe zone below
int current_wall_phase; // 0 = building wall 0, 1 = building wall 1, 2 = done

// Edge-inward column order: 1, 30, 2, 29, 3, 28, ...
std::vector<int> edge_inward_order() {
    std::vector<int> order;
    int lo = 1, hi = GRID_SIZE;
    while (lo <= hi) {
        order.push_back(lo);
        if (lo != hi) order.push_back(hi);
        lo++;
        hi--;
    }
    return order;
}

void choose_walls() {
    // Find the best wall row pair for sequential building
    // Wall 1: build first, should be fast and reliable (no pets in safe zone)
    // Wall 2: build second, also try to have no pets in safe zone

    double best_score = -1;
    int best_r1 = -1, best_r2 = -1;
    int best_side1 = -1, best_side2 = 1;

    // Try all combinations: wall from top edge, wall from bottom edge
    for (int r1 = 2; r1 <= 14; r1++) {
        // Wall 1 at row r1, safe zone above (rows 1 to r1-1)
        int pets_above_r1 = 0;
        for (auto& p : pets) {
            if (p.r < r1) pets_above_r1++;
        }

        int area1 = (r1 - 1) * GRID_SIZE;
        double score1 = (double)area1 / 900.0 * std::pow(2.0, -(double)pets_above_r1);

        for (int r2 = r1 + 3; r2 <= 29; r2++) {
            // Wall 2 at row r2, safe zone below (rows r2+1 to 30)
            int pets_below_r2 = 0;
            for (auto& p : pets) {
