            // All humans share both zones (they'll go to the better one)
            // Actually we'll split: those closer to wall1 go above, those closer to wall2 go below
            double avg_score = (score1 + score2) / 2.0;

            // Penalize by human travel time
            double avg_dist = 0;
            for (int i = 0; i < M; i++) {
                double d1 = std::abs(humans[i].r - r1);
                double d2 = std::abs(humans[i].r - r2);
                avg_dist += std::min(d1, d2);
            }
            avg_dist /= M;

            // Heavily penalize having pets in safe zone (they're trapped forever)
            double leakage_penalty = 1.0;
            if (pets_above_r1 > 0) leakage_penalty *= 0.3;
            if (pets_below_r2 > 0) leakage_penalty *= 0.3;

            // Prefer walls closer to edges (faster build, less leakage)
            double proximity_bonus = 1.0 / (1.0 + avg_dist * 0.02);

            double total = avg_score * leakage_penalty * proximity_bonus;

            if (total > best_score) {
                best_score = total;
                best_r1 = r1;
                best_r2 = r2;
                best_side1 = -1; // safe above
                best_side2 = 1;  // safe below
            }
        }
    }

    // Also try: both walls from same side (two walls near top creating deep safe zone at top)
    // Or single wall only
    double best_single_score = -1;
    int best_single_r = -1;
    int best_single_side = -1;

    for (int r = 2; r <= 29; r++) {
        int pets_above = 0, pets_below = 0;
