        double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
        double penalty_a = (pets_above > 0) ? 0.3 : 1.0;

        // Safe below
        int area_below = (GRID_SIZE - r) * GRID_SIZE;
        double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
        double penalty_b = (pets_below > 0) ? 0.3 : 1.0;

        double avg_d = 0;
        for (int i = 0; i < M; i++) avg_d += std::abs(humans[i].r - r);
        avg_d /= M;
        double prox = 1.0 / (1.0 + avg_d * 0.02);

        if (sa * penalty_a * prox > best_single_score) {
            best_single_score = sa * penalty_a * prox;
            best_single_r = r;
            best_single_side = -1;
        }
        if (sb * penalty_b * prox > best_single_score) {
            best_single_score = sb * penalty_b * prox;
            best_single_r = r;
            best_single_side = 1;
        }
    }

    // Decide: dual or single wall
    // Single wall takes half the construction time but gives less area
    // Use dual if significantly better
