        assign_humans_lshape();
    } else {
        assign_humans_dual_h();
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (strategy_mode == 0) {
            for (int i = 0; i < M; i++) {
                int my_plan = human_plan_assignment[i];
                auto& my_walls = plan_walls[my_plan];
                auto& plan = plans[my_plan];

                // Find nearest unbuilt wall cell (prefer cells that can be built now)
                int best_idx = -1;
                int best_dist = INF;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    // Compute distance to best standing position for this wall cell
                    int min_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wc.r + DR[d], sc = wc.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        // Strongly prefer safe-side positions
                        bool in_safe = is_safe_side(plan, sr, sc);
                        int sdist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        if (!in_safe) sdist += 50;
                        min_stand_dist = std::min(min_stand_dist, sdist);
                    }

                    if (min_stand_dist < best_dist) {
                        best_dist = min_stand_dist;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // All walls built - ensure human is in safe zone
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = plan.r_min; r <= plan.r_max; r++) {
                            for (int c = plan.c_min; c <= plan.c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_safe; }
                            }
                        }
                        found_safe:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    Point wall_target = my_walls[best_idx];

                    // Find best standing position (prefer inside safe zone)
                    Point stand_pos = {-1, -1};
                    int best_stand_d = INF;

                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_safe_side(plan, sr, sc);
                        int sdist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        if (!in_safe) sdist += 50;
                        if (sdist < best_stand_d) {
                            best_stand_d = sdist;
