# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Strategy: Build L-shaped walls in two opposite corners, sealing off pet-free zones.
// Each corner has 2 free boundary walls, so only need 2 wall segments.
// This is much cheaper than full horizontal walls and adapts to pet positions.

struct CornerPlan {
    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
    int wall_row; // the horizontal wall row
    int wall_col; // the vertical wall column
    int area;
    int cost; // number of wall cells needed
    int pets_inside;
    double score;
    // The sealed region boundaries
    int r_min, r_max, c_min, c_max;
};

// Wall cells for a corner plan
std::vector<Point> get_wall_cells(const CornerPlan& plan) {
    std::vector<Point> cells;
    if (plan.corner == 0) { // Top-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows 1..wall_row-1)
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 1) { // Top-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows 1..wall_row-1)
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 2) { // Bottom-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows wall_row+1..30)
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    } else { // Bottom-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows wall_row+1..30)
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    }
    return cells;
}

bool is_safe_side(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
}

// Find the best pair of corners (opposite corners)
CornerPlan plans[2];
int num_plans;

void find_best_corner(int corner_id, CornerPlan& best) {
    best.score = -1;

    for (int wr = 2; wr <= 29; wr++) {
        for (int wc = 2; wc <= 29; wc++) {
            int pets_inside = 0;
            int area = 0;
            int cost = 0;
            int r_min, r_max, c_min, c_max;

            if (corner_id == 0) { // Top-Left: sealed region [1..wr-1] x [1..wc-1]
                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
                cost = wc + (wr - 1); // horizontal wall has wc cells, vertical has wr-1 cells
            } else if (corner_id == 1) { // Top-Right: sealed region [1..wr-1] x [wc+1..30]
                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (wr - 1);
            } else if (corner_id == 2) { // Bottom-Left: sealed region [wr+1..30] x [1..wc-1]
                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
                cost = wc + (GRID_SIZE - wr);
            } else { // Bottom-Right: sealed region [wr+1..30] x [wc+1..30]
                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
            }

            area = (r_max - r_min + 1) * (c_max - c_min + 1);
            if (area < 50) continue; // too small
            if (cost > 40) continue; // too expensive

            for (auto& p : pets) {
                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
                    pets_inside++;
                }
            }

            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);

            // Penalize by construction cost (more cells = more time = more leakage)
            double time_factor = 1.0 / (1.0 + cost * 0.01);

            // Heavily reward 0 pets inside
            double pet_bonus = (pets_inside == 0) ? 2.0 : 1.0;

            double score = base_score * time_factor * pet_bonus;

            if (score > best.score) {
                best.corner = corner_id;
                best.wall_row = wr;
                best.wall_col = wc;
                best.area = area;
                best.cost = cost;
                best.pets_inside = pets_inside;
                best.score = score;
                best.r_min = r_min;
                best.r_max = r_max;
                best.c_min = c_min;
                best.c_max = c_max;
            }
        }
    }
}

// Also compute dual horizontal wall score for comparison
double compute_dual_wall_score(int tr, int br) {
    int pets_above = 0, pets_below = 0;
    for (auto& p : pets) {
        if (p.r < tr) pets_above++;
        else if (p.r > br) pets_below++;
    }
    int area_above = (tr - 1) * GRID_SIZE;
    int area_below = (GRID_SIZE - br) * GRID_SIZE;
    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
    return (sa + sb) / 2.0;
}

// Mode: 0 = dual L-shape, 1 = dual horizontal walls (fallback)
int strategy_mode;
int dual_wall_top, dual_wall_bot;

void choose_strategy() {
    // Find best corner plans for each corner
    CornerPlan corners[4];
    for (int i = 0; i < 4; i++) {
        find_best_corner(i, corners[i]);
    }

    // Best pair of opposite corners
    double best_pair_score = -1;
    int best_pair[2] = {0, 3};

    // Opposite pairs: (TL,BR) and (TR,BL)
    int pairs[2][2] = {{0, 3}, {1, 2}};
    for (auto& pair : pairs) {
        double combined = corners[pair[0]].score + corners[pair[1]].score;
        if (combined > best_pair_score) {
            best_pair_score = combined;
            best_pair[0] = pair[0];
            best_pair[1] = pair[1];
        }
    }

    // Also try single best corner (all humans in one corner)
    double best_single_score = -1;
    int best_single = 0;
    for (int i = 0; i < 4; i++) {
        if (corners[i].score > best_single_score) {
            best_single_score = corners[i].score;
            best_single = i;
        }
    }

    // Compare with dual horizontal walls
    double best_dual_h = -1;
    int best_tr = 8, best_br = 23;
    for (int tr = 3; tr <= 15; tr++) {
        for (int br = tr + 4; br <= 28; br++) {
            double s = compute_dual_wall_score(tr, br);
            if (s > best_dual_h) {
                best_dual_h = s;
                best_tr = tr;
                best_br = br;
            }
        }
    }

    // Choose strategy
    // L-shape advantages: faster build, better pet isolation when corners are clean
    // Give L-shape a 20% bonus for faster construction
    double l_pair_effective = best_pair_score * 1.2;
    double l_single_effective = best_single_score * 1.3; // single is even faster

    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
        strategy_mode = 0;
        num_plans = 2;
        plans[0] = corners[best_pair[0]];
        plans[1] = corners[best_pair[1]];
    } else if (l_single_effective > best_dual_h) {
        strategy_mode = 0;
        num_plans = 1;
        plans[0] = corners[best_single];
    } else {
        strategy_mode = 1;
        dual_wall_top = best_tr;
        dual_wall_bot = best_br;
    }
}

// Human assignment for L-shape strategy
int human_plan_assignment[10]; // which plan (0 or 1)

// Wall cells to build for each plan
std::vector<Point> plan_walls[2];

void assign_humans_lshape() {
    if (num_plans == 1) {
        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
        return;
    }

    // Split humans between two plans based on proximity
    int count0 = M / 2;

    std::vector<std::pair<double, int>> preference(M);
    for (int i = 0; i < M; i++) {
        // Distance to center of plan 0 region
        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);

        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);

        preference[i] = {d0 - d1, i};
    }
    std::sort(preference.begin(), preference.end());

    int assigned0 = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned0 < count0) {
            human_plan_assignment[idx] = 0;
            assigned0++;
        } else {
            human_plan_assignment[idx] = 1;
        }
    }
}

// For dual horizontal wall fallback
int human_wall_assignment_h[10]; // 0=top, 1=bot

void assign_humans_dual_h() {
    int top_count = M / 2;
    std::vector<std::pair<int, int>> preference(M);
    for (int i = 0; i < M; i++) {
        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
    }
    std::sort(preference.begin(), preference.end());
    int assigned_top = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned_top < top_count) {
            human_wall_assignment_h[idx] = 0;
            assigned_top++;
        } else {
            human_wall_assignment_h[idx] = 1;
        }
    }
}

int main() {
