                int best_idx = -1;
                int best_dist = INF;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    // Check not already claimed this turn
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) {
                        best_dist = dist;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // All walls built - move to center of safe zone
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        // Find any passable cell in safe zone
                        bool found = false;
                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
                                if (passable(r, c)) {
                                    target = {r, c};
                                    found = true;
                                }
                            }
                        }
                    }
                    if (humans[i] != target) {
                        actions[i] = move_toward(humans[i], target);
                    }
                } else {
                    Point wall_target = my_walls[best_idx];

                    // Find a position adjacent to wall_target from the SAFE side
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;

                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;

                        // Prefer standing inside the safe zone
                        bool in_safe = is_safe_side(plan, sr, sc);

                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        // Give big bonus to safe-side positions
                        int effective_dist = in_safe ? dist : dist + 100;

                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }

                    if (stand_pos.r == -1) {
                        // Can't find standing position, try any adjacent
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d];
                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) {
