217	// Also compute dual horizontal wall score for comparison
218	double compute_dual_wall_score(int tr, int br) {
219	    int pets_above = 0, pets_below = 0;
220	    for (auto& p : pets) {
221	        if (p.r < tr) pets_above++;
222	        else if (p.r > br) pets_below++;
223	    }
224	    int area_above = (tr - 1) * GRID_SIZE;
225	    int area_below = (GRID_SIZE - br) * GRID_SIZE;
226	    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
227	    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
228	    return (sa + sb) / 2.0;
229	}
