316	// Human assignment for L-shape strategy
317	int human_plan_assignment[10]; // which plan (0 or 1)
318	
319	// Wall cells to build for each plan
320	std::vector<Point> plan_walls[2];
321	
322	void assign_humans_lshape() {
323	    if (num_plans == 1) {
324	        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
325	        return;
326	    }
327	
328	    // Split humans between two plans based on proximity
329	    int count0 = M / 2;
330	
331	    std::vector<std::pair<double, int>> preference(M);
332	    for (int i = 0; i < M; i++) {
333	        // Distance to center of plan 0 region
334	        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
335	        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
336	        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
337	
338	        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
339	        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
340	        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
341	
342	        preference[i] = {d0 - d1, i};
343	    }
344	    std::sort(preference.begin(), preference.end());
345	
346	    int assigned0 = 0;
347	    for (auto& [pref, idx] : preference) {
348	        if (assigned0 < count0) {
349	            human_plan_assignment[idx] = 0;
350	            assigned0++;
351	        } else {
352	            human_plan_assignment[idx] = 1;
353	        }
354	    }
355	}
356	
357	// For dual horizontal wall fallback
358	int human_wall_assignment_h[10]; // 0=top, 1=bot
359	
360	void assign_humans_dual_h() {
361	    int top_count = M / 2;
362	    std::vector<std::pair<int, int>> preference(M);
363	    for (int i = 0; i < M; i++) {
364	        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
365	    }
366	    std::sort(preference.begin(), preference.end());
367	    int assigned_top = 0;
368	    for (auto& [pref, idx] : preference) {
369	        if (assigned_top < top_count) {
370	            human_wall_assignment_h[idx] = 0;
371	            assigned_top++;
372	        } else {
373	            human_wall_assignment_h[idx] = 1;
374	        }
375	    }
376	}
